1	// Shared URL-state helper for list views (artifacts, etc.).
2	// Reads/writes the well-known query params (q, mediaType, groupBy, sort,
3	// filters.*) while preserving any unrelated keys, including ?back=.
4	
5	export type GroupBy = 'folder' | 'prefix' | 'mediaType'
6	
7	const KNOWN_KEYS = new Set(['q', 'mediaType', 'groupBy', 'sort', 'staleness'])
8	const FILTER_PREFIX = 'filter.'
9	
10	export interface ListURLState {
11		q: string
12		mediaType: string | null
13		groupBy: GroupBy
14		sort: string | null
15		staleness: string | null
16		filters: Record<string, string>
17	}
18	
19	export const DEFAULT_GROUP_BY: GroupBy = 'folder'
20	
21	function parseGroupBy(raw: string | null): GroupBy {
22		if (raw === 'prefix' || raw === 'mediaType' || raw === 'folder') return raw
23		return DEFAULT_GROUP_BY
24	}
25	
26	export function readState(params: URLSearchParams): ListURLState {
27		const filters: Record<string, string> = {}
28		for (const [k, v] of params.entries()) {
29			if (k.startsWith(FILTER_PREFIX)) filters[k.slice(FILTER_PREFIX.length)] = v
30		}
31		return {
32			q: params.get('q') ?? '',
33			mediaType: params.get('mediaType'),
34			groupBy: parseGroupBy(params.get('groupBy')),
35			sort: params.get('sort'),
36			staleness: params.get('staleness'),
37			filters
38		}
39	}
40	
41	// writeState mutates a copy of `params` with the patch applied. Unrelated
42	// keys (including `back`) are preserved. Empty/null values delete the key.
43	export function writeState(
44		params: URLSearchParams,
45		patch: Partial<ListURLState>
46	): URLSearchParams {
47		const next = new URLSearchParams(params)
48	
49		if ('q' in patch) {
50			if (patch.q) next.set('q', patch.q)
51			else next.delete('q')
52		}
53		if ('mediaType' in patch) {
54			if (patch.mediaType) next.set('mediaType', patch.mediaType)
55			else next.delete('mediaType')
56		}
57		if ('groupBy' in patch) {
58			if (patch.groupBy && patch.groupBy !== DEFAULT_GROUP_BY) next.set('groupBy', patch.groupBy)
59			else next.delete('groupBy')
60		}
61		if ('sort' in patch) {
62			if (patch.sort) next.set('sort', patch.sort)
63			else next.delete('sort')
64		}
65		if ('staleness' in patch) {
66			if (patch.staleness) next.set('staleness', patch.staleness)
67			else next.delete('staleness')
68		}
69		if ('filters' in patch && patch.filters) {
70			// Replace only the filter.* keys; leave everything else intact.
71			for (const k of Array.from(next.keys())) {
72				if (k.startsWith(FILTER_PREFIX)) next.delete(k)
73			}
74			for (const [k, v] of Object.entries(patch.filters)) {
75				if (v) next.set(FILTER_PREFIX + k, v)
76			}
77		}
78	
79		return next
80	}
81	
82	// Build a back-href that captures the current pathname + relevant search.
83	export function backHref(pathname: string, params: URLSearchParams): string {
84		const s = params.toString()
85		return s ? `${pathname}?${s}` : pathname
86	}
