1	import { expect, test } from '@playwright/test';
2	
3	// Seeded fixture: an artifact with known generated_by metadata (US-081b).
4	const NODE_INFO = { id: 'node-abc', name: 'Test Node' };
5	const PROJECT_ID = 'proj-1';
6	const PROJECTS = [{ id: PROJECT_ID, name: 'Project Alpha', path: '/repos/alpha' }];
7	
8	const ARTIFACT_GENERATED = {
9		id: 'artifact-generated-001',
10		path: 'docs/generated/report.md',
11		title: 'Generated Report',
12		mediaType: 'text/markdown',
13		staleness: 'fresh',
14		description: 'Synthesized report',
15		updatedAt: '2026-04-30T12:00:00Z',
16		ddxFrontmatter: JSON.stringify({ id: 'artifact-generated-001' }),
17		content: '# Generated Report\n\nBody text.\n',
18		generatedBy: {
19			runId: 'run-source-123',
20			promptSummary: 'synthesize report from latest data',
21			sourceHashMatch: true
22		}
23	};
24	
25	const ARTIFACT_PLAIN = {
26		id: 'artifact-plain-001',
27		path: 'docs/manual.md',
28		title: 'Manual Doc',
29		mediaType: 'text/markdown',
30		staleness: 'fresh',
31		description: null,
32		updatedAt: '2026-04-30T12:00:00Z',
33		ddxFrontmatter: null,
34		content: '# Manual\n',
35		generatedBy: null
36	};
37	
38	const REGENERATE_RUN_ID = 'regen-artifact-generated-001-deadbeef';
39	
40	const BASE_URL = `/nodes/${NODE_INFO.id}/projects/${PROJECT_ID}/artifacts`;
41	
42	interface MockState {
43		regenerateCalled: boolean;
44		lastArtifactId: string | null;
45	}
46	
47	async function mockRoutes(page: import('@playwright/test').Page, state: MockState) {
48		await page.route('/graphql', async (route) => {
49			const body = route.request().postDataJSON() as {
50				query: string;
51				variables?: Record<string, string>;
52			};
53			const q = body.query;
54	
55			if (q.includes('NodeInfo')) {
56				await route.fulfill({
57					status: 200,
58					contentType: 'application/json',
59					body: JSON.stringify({ data: { nodeInfo: NODE_INFO } })
60				});
61				return;
62			}
63			if (q.includes('Projects') && !q.includes('projectID')) {
64				await route.fulfill({
65					status: 200,
66					contentType: 'application/json',
67					body: JSON.stringify({
68						data: { projects: { edges: PROJECTS.map((p) => ({ node: p })) } }
69					})
70				});
71				return;
72			}
73			if (q.includes('query Artifacts(') || q.includes('ArtifactsByPath')) {
74				const list = [ARTIFACT_GENERATED, ARTIFACT_PLAIN];
75				const search = body.variables?.search;
76				const filtered = search
77					? list.filter(
78							(a) =>
79								a.title.toLowerCase().includes(String(search).toLowerCase()) ||
80								a.path.toLowerCase().includes(String(search).toLowerCase())
81						)
82					: list;
83				await route.fulfill({
84					status: 200,
85					contentType: 'application/json',
86					body: JSON.stringify({
87						data: {
88							artifacts: {
89								edges: filtered.map((a, i) => ({
90									node: {
91										id: a.id,
92										path: a.path,
93										title: a.title,
94										mediaType: a.mediaType,
95										staleness: a.staleness
96									},
97									cursor: `c${i}`
98								})),
99								pageInfo: { hasNextPage: false, endCursor: null },
100								totalCount: filtered.length
101							}
102						}
103					})
104				});
105				return;
106			}
107			if (q.includes('ArtifactDetail')) {
108				const id = body.variables?.id;
109				const match = [ARTIFACT_GENERATED, ARTIFACT_PLAIN].find((a) => a.id === id);
110				await route.fulfill({
111					status: 200,
112					contentType: 'application/json',
113					body: JSON.stringify({ data: { artifact: match ?? null } })
114				});
115				return;
116			}
117			if (q.includes('RunExists')) {
118				const id = body.variables?.id;
119				await route.fulfill({
120					status: 200,
121					contentType: 'application/json',
122					body: JSON.stringify({
123						data: { run: id === ARTIFACT_GENERATED.generatedBy.runId ? { id } : null }
124					})
125				});
126				return;
127			}
128			if (q.includes('mutation ArtifactRegenerate')) {
129				state.regenerateCalled = true;
130				state.lastArtifactId = body.variables?.artifactId ?? null;
131				await route.fulfill({
132					status: 200,
133					contentType: 'application/json',
134					body: JSON.stringify({
135						data: {
136							artifactRegenerate: { runId: REGENERATE_RUN_ID, status: 'queued' }
137						}
138					})
139				});
140				return;
141			}
142			if (q.includes('Run(') || q.includes('query Run')) {
143				await route.fulfill({
144					status: 200,
145					contentType: 'application/json',
146					body: JSON.stringify({ data: { run: { id: REGENERATE_RUN_ID } } })
147				});
148				return;
149			}
150			await route.continue();
151		});
152	}
