154	// Full US-081b workflow: list → filter → open → renderer → provenance →
155	// Regenerate → run id shown → follow run link → navigate back to artifact.
156	test('US-081b end-to-end: list → filter → open → regenerate → run link → back', async ({
157		page
158	}) => {
159		const state: MockState = { regenerateCalled: false, lastArtifactId: null };
160		await mockRoutes(page, state);
161	
162		// 1. List
163		await page.goto(BASE_URL);
164		await expect(page.getByText('Generated Report')).toBeVisible();
165		await expect(page.getByText('Manual Doc')).toBeVisible();
166	
167		// 2. Filter (search) — narrow to the generated artifact via path/title.
168		const search = page.getByPlaceholder(/Search/i).first();
169		await search.fill('Generated');
170		await expect(page.getByText('Generated Report')).toBeVisible();
171	
172		// 3. Open
173		await page.getByText('Generated Report').first().click();
174		await expect(page).toHaveURL(new RegExp(`/artifacts/${ARTIFACT_GENERATED.id}`));
175	
176		// 4. Verify renderer (markdown body shown). The page renders the artifact
177		//    title as <h1> and the markdown body also renders <h1># Generated
178		//    Report</h1>, so we use .first() to disambiguate without weakening the
179		//    visibility assertion.
180		await expect(page.getByRole('heading', { name: 'Generated Report' }).first()).toBeVisible();
181		await expect(page.getByText(/Body text\./)).toBeVisible();
182	
183		// 5. Provenance panel visible.
184		await expect(page.getByTestId('provenance-panel')).toBeVisible();
185	
186		// 6. Click Regenerate.
187		await page.getByTestId('regenerate-button').click();
188	
189		// 7. Verify run id shown + dispatched mutation called.
190		const runLink = page.getByTestId('regenerate-run-link');
191		await expect(runLink).toBeVisible();
192		await expect(runLink).toHaveText(REGENERATE_RUN_ID);
193		expect(state.regenerateCalled).toBe(true);
194		expect(state.lastArtifactId).toBe(ARTIFACT_GENERATED.id);
195	
196		// 8. Follow run link.
197		await runLink.click();
198		await expect(page).toHaveURL(
199			new RegExp(`/runs/${encodeURIComponent(REGENERATE_RUN_ID).replace(/-/g, '\\-')}`)
200		);
201	
202		// 9. Navigate back to artifact.
203		await page.goBack();
204		await expect(page).toHaveURL(new RegExp(`/artifacts/${ARTIFACT_GENERATED.id}`));
205		await expect(page.getByTestId('provenance-panel')).toBeVisible();
206	});
