208	// Regenerate button is hidden when generatedBy is absent (AC#2).
209	test('Regenerate button is not shown when generatedBy is absent', async ({ page }) => {
210		const state: MockState = { regenerateCalled: false, lastArtifactId: null };
211		await mockRoutes(page, state);
212	
213		await page.goto(`${BASE_URL}/${ARTIFACT_PLAIN.id}`);
214		await expect(page.getByRole('heading', { name: 'Manual Doc' })).toBeVisible();
215		await expect(page.getByTestId('provenance-panel')).toHaveCount(0);
216		await expect(page.getByTestId('regenerate-button')).toHaveCount(0);
217	});
