219	// Sort dropdown + staleness chips + search composition (Story 6).
220	// Verifies: (1) controls render, (2) URL state round-trips, (3) each param
221	// change re-issues the query (cursor reset) with the merged variables.
222	test('artifacts: sort + staleness chips + search compose into URL state and refetch', async ({
223		page
224	}) => {
225		const calls: { variables: Record<string, unknown> | undefined; after: unknown }[] = []
226		const listArtifacts = [
227			{
228				id: 'a-1',
229				path: 'docs/alpha.md',
230				title: 'Alpha',
231				mediaType: 'text/markdown',
232				staleness: 'fresh'
233			},
234			{
235				id: 'a-2',
236				path: 'docs/beta.md',
237				title: 'Beta',
238				mediaType: 'text/markdown',
239				staleness: 'stale'
240			},
241			{
242				id: 'a-3',
243				path: 'docs/gamma.md',
244				title: 'Gamma',
245				mediaType: 'text/markdown',
246				staleness: 'missing'
247			}
248		]
249		await page.route('/graphql', async (route) => {
250			const body = route.request().postDataJSON() as {
251				query: string
252				variables?: Record<string, unknown>
253			}
254			const q = body.query
255			if (q.includes('NodeInfo')) {
256				await route.fulfill({
257					status: 200,
258					contentType: 'application/json',
259					body: JSON.stringify({ data: { nodeInfo: NODE_INFO } })
260				})
261				return
262			}
263			if (q.includes('Projects') && !q.includes('projectID')) {
264				await route.fulfill({
265					status: 200,
266					contentType: 'application/json',
267					body: JSON.stringify({
268						data: { projects: { edges: PROJECTS.map((p) => ({ node: p })) } }
269					})
270				})
271				return
272			}
273			if (q.includes('query Artifacts(')) {
274				calls.push({ variables: body.variables, after: body.variables?.after ?? null })
275				const v = body.variables ?? {}
276				let filtered = listArtifacts
277				if (v.staleness) filtered = filtered.filter((a) => a.staleness === v.staleness)
278				if (v.search) {
279					const s = String(v.search).toLowerCase()
280					filtered = filtered.filter(
281						(a) => a.title.toLowerCase().includes(s) || a.path.toLowerCase().includes(s)
282					)
283				}
284				if (v.sort === 'TITLE') {
285					filtered = [...filtered].sort((a, b) => a.title.localeCompare(b.title))
286				}
287				await route.fulfill({
288					status: 200,
289					contentType: 'application/json',
290					body: JSON.stringify({
291						data: {
292							artifacts: {
293								edges: filtered.map((a, i) => ({
294									node: a,
295									cursor: `c${i}`
296								})),
297								pageInfo: { hasNextPage: false, endCursor: null },
298								totalCount: filtered.length
299							}
300						}
301					})
302				})
303				return
304			}
305			await route.continue()
306		})
307	
308		// 1. Initial load — sort dropdown + staleness chips visible.
309		await page.goto(BASE_URL)
310		await expect(page.getByTestId('sort-select')).toBeVisible()
311		await expect(page.getByTestId('staleness-chip-fresh')).toBeVisible()
312		await expect(page.getByTestId('staleness-chip-stale')).toBeVisible()
313		await expect(page.getByTestId('staleness-chip-missing')).toBeVisible()
314		await expect(page.getByRole('cell', { name: 'Alpha', exact: true })).toBeVisible()
315	
316		// 2. Change sort → URL gains ?sort=TITLE and a refetch is issued.
317		const callsBefore = calls.length
318		await page.getByTestId('sort-select').selectOption('TITLE')
319		await expect(page).toHaveURL(/[?&]sort=TITLE\b/)
320		await expect.poll(() => calls.length).toBeGreaterThan(callsBefore)
321		expect(calls[calls.length - 1].variables?.sort).toBe('TITLE')
322		expect(calls[calls.length - 1].after).toBeNull()
323	
324		// 3. Toggle staleness=stale chip → URL gains ?staleness=stale and refetches
325		//    (cursor reset: `after` is null on the new request).
326		const beforeStale = calls.length
327		await page.getByTestId('staleness-chip-stale').click()
328		await expect(page).toHaveURL(/[?&]staleness=stale\b/)
329		await expect.poll(() => calls.length).toBeGreaterThan(beforeStale)
330		expect(calls[calls.length - 1].variables?.staleness).toBe('stale')
331		expect(calls[calls.length - 1].variables?.sort).toBe('TITLE')
332		expect(calls[calls.length - 1].after).toBeNull()
333		await expect(page.getByRole('cell', { name: 'Beta', exact: true })).toBeVisible()
334		await expect(page.getByRole('cell', { name: 'Alpha', exact: true })).toHaveCount(0)
335	
336		// 4. Add search → params compose; URL contains all three; refetch issued.
337		const beforeSearch = calls.length
338		await page.getByPlaceholder(/Search/i).first().fill('beta')
339		await expect.poll(() => calls.length).toBeGreaterThan(beforeSearch)
340		await expect(page).toHaveURL(/[?&]q=beta\b/)
341		await expect(page).toHaveURL(/[?&]sort=TITLE\b/)
342		await expect(page).toHaveURL(/[?&]staleness=stale\b/)
343		const last = calls[calls.length - 1]
344		expect(last.variables?.search).toBe('beta')
345		expect(last.variables?.sort).toBe('TITLE')
346		expect(last.variables?.staleness).toBe('stale')
347		expect(last.after).toBeNull()
348	
349		// 5. Toggle staleness chip off → param removed; refetch reflects null.
350		const beforeClear = calls.length
351		await page.getByTestId('staleness-chip-stale').click()
352		await expect.poll(() => calls.length).toBeGreaterThan(beforeClear)
353		await expect(page).not.toHaveURL(/[?&]staleness=/)
354		expect(calls[calls.length - 1].variables?.staleness).toBeUndefined()
355	})
