357	// Mutation error path: server returns a typed error → inline message in the
358	// provenance panel, page does not crash (AC#4).
359	test('Regenerate error renders inline without crashing the page', async ({ page }) => {
360		const state: MockState = { regenerateCalled: false, lastArtifactId: null };
361		await mockRoutes(page, state);
362		// Override only the mutation to return a typed error.
363		await page.route('/graphql', async (route) => {
364			const body = route.request().postDataJSON() as { query: string };
365			if (body.query.includes('mutation ArtifactRegenerate')) {
366				await route.fulfill({
367					status: 200,
368					contentType: 'application/json',
369					body: JSON.stringify({
370						data: null,
371						errors: [
372							{
373								message: 'regeneration backend unavailable',
374								extensions: { code: 'INTERNAL_ERROR' }
375							}
376						]
377					})
378				});
379				return;
380			}
381			await route.fallback();
382		});
383	
384		await page.goto(`${BASE_URL}/${ARTIFACT_GENERATED.id}`);
385		await page.getByTestId('regenerate-button').click();
386		await expect(page.getByTestId('regenerate-error')).toContainText(
387			/regeneration backend unavailable/
388		);
389		// Page is still alive.
390		await expect(page.getByRole('heading', { name: 'Generated Report' }).first()).toBeVisible();
391	});
